ActivityListener = {}

function ActivityListener:init()
    BedWarReceivedFirstRechargeEvent:registerCallBack(self.onBedWarReceivedFirstRecharge)
    BedWarTiroSignInEvent:registerCallBack(self.onBedWarTiroSignIn)
    BedWarReceivedSuperPlayerEvent:registerCallBack(self.onBedWarReceivedSuperPlayer)
    BedWarDailySignInEvent:registerCallBack(self.onBedWarDailySignIn)
    CloseVideoAdTipEvent:registerCallBack(self.onCloseVideoAdTip)
    SignInAgainEvent:registerCallBack(self.onSignInAgain)
end

function ActivityListener.onBedWarReceivedFirstRecharge(userId, data)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return
    end
    if not DbUtil:IsGetAllDataFinished(player) then
        return
    end
    GameActivity:receiveFirstRechargeRewards(player)
end

function ActivityListener.onBedWarTiroSignIn(userId, data)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return
    end
    if not DbUtil:IsGetAllDataFinished(player) then
        return
    end
    GameActivity:receiveTiroSignInRewards(player)
end

function ActivityListener.onBedWarReceivedSuperPlayer(userId, data)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return
    end
    if not DbUtil:IsGetAllDataFinished(player) then
        return
    end
    GameActivity:receiveSuperPlayerRewards(player)
